#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <limits.h>

typedef unsigned long long ull;
const ull INF = (ull)1e18;

int countLuckyDigits(int x) {
    int count = 0;
    while (x > 0) {
        int digit = x % 10;
        if (digit == 4 || digit == 7) {
            count++;
        }
        x /= 10;
    }
    return count;
}

void findKthLuckySequence(int n, int m, int k, int* C) {
    int* sequence = (int*)malloc(n * sizeof(int));
    int* count = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        sequence[i] = 0;
        count[i] = 0;
    }
    int index = 0;
    while (k > 0) {
        for (int i = 1; i <= m; i++) {
            int luckyDigits = countLuckyDigits(i);
            if (index == 0 || (C[index - 1] == 1 && luckyDigits == count[index - 1]) || (C[index - 1] == 0 && luckyDigits != count[index - 1])) {
                sequence[index] = i;
                count[index] = luckyDigits;
                k--;
                if (k == 0) {
                    break;
                }
            }
        }
        index++;
    }
    if (k > 0) {
        printf("-1\n");
    } else {
        for (int i = 0; i < n; i++) {
            printf("%d ", sequence[i]);
        }
        printf("\n");
    }
    free(sequence);
    free(count);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T-- > 0) {
        int n, m, k;
        scanf("%d %d %d", &n, &m, &k);
